type ModeWriter = (doc: Doc, modes: { execution: "sync" | "async" }) => void;

export class Doc {
  args!: string[];
  content: string[] = [];
  indent = 0;

  constructor(args: string[] = []) {
    if (this) this.args = args;
  }

  indented(fn: (doc: Doc) => void) {
    this.indent += 1;
    fn(this);
    this.indent -= 1;
  }

  write(fn: ModeWriter): void;
  write(line: string): void;
  write(arg: any) {
    if (typeof arg === "function") {
      (arg as ModeWriter)(this, { execution: "sync" });
      (arg as ModeWriter)(this, { execution: "async" });
      return;
    }

    const content = arg as string;
    const lines = content.split("\n").filter((x) => x);
    const minIndent = Math.min(...lines.map((x) => x.length - x.trimStart().length));
    const dedented = lines.map((x) => x.slice(minIndent)).map((x) => " ".repeat(this.indent * 2) + x);
    for (const line of dedented) {
      this.content.push(line);
    }
  }

  compile(): any {
    const F = Function;
    const args = this?.args;
    const content = this?.content ?? [``];
    const lines = [...content.map((x) => `  ${x}`)];
    // console.log(lines.join("\n"));
    return new F(...args, lines.join("\n")) as any;
  }
}

import { useCallback, useEffect, useState } from 'react';

export interface UseMouseReturnValue<T extends HTMLElement = any> {
  ref: React.RefCallback<T | null>;
  x: number;
  y: number;
}

export function useMouse<T extends HTMLElement = any>(
  options: { resetOnExit?: boolean } = { resetOnExit: false }
): UseMouseReturnValue<T> {
  const [position, setPosition] = useState({ x: 0, y: 0 });

  const refCallback: React.RefCallback<T | null> = useCallback(
    (node) => {
      const setMousePosition = (event: Event) => {
        const mouseEvent = event as globalThis.MouseEvent;
        if (node) {
          const rect = node.getBoundingClientRect();

          const x = Math.max(0, Math.round(mouseEvent.clientX - rect.left));

          const y = Math.max(0, Math.round(mouseEvent.clientY - rect.top));

          setPosition({ x, y });
        } else {
          setPosition({ x: mouseEvent.clientX, y: mouseEvent.clientY });
        }
      };

      const resetMousePosition = () => setPosition({ x: 0, y: 0 });

      node?.addEventListener('mousemove', setMousePosition);
      if (options.resetOnExit) {
        node?.addEventListener('mouseleave', resetMousePosition);
      }

      return () => {
        node?.removeEventListener('mousemove', setMousePosition);
        if (options.resetOnExit) {
          node?.removeEventListener('mouseleave', resetMousePosition);
        }
      };
    },
    [options.resetOnExit]
  );

  return { ref: refCallback, ...position };
}

import { useCallback, useState } from 'react';
import { clamp } from '../utils';

const DEFAULT_OPTIONS = {
  min: -Infinity,
  max: Infinity,
};

export interface UseCounterOptions {
  min?: number;
  max?: number;
  step?: number;
}

export interface UseCounterHandlers {
  increment: () => void;
  decrement: () => void;
  set: (value: number) => void;
  reset: () => void;
}

export type UseCounterReturnValue = [number, UseCounterHandlers];

export function useCounter(initialValue = 0, options?: UseCounterOptions): UseCounterReturnValue {
  const { min, max, step: _step = 1 } = { ...DEFAULT_OPTIONS, ...options };
  const step = Math.abs(_step);
  const [count, setCount] = useState<number>(clamp(initialValue, min, max));

  const increment = useCallback(
    () => setCount((current) => clamp(current + step, min, max)),
    [min, max, step]
  );

  const decrement = useCallback(
    () => setCount((current) => clamp(current - step, min, max)),
    [min, max, step]
  );

  const set = useCallback((value: number) => setCount(clamp(value, min, max)), [min, max]);

  const reset = useCallback(
    () => setCount(clamp(initialValue, min, max)),
    [initialValue, min, max]
  );

  return [count, { increment, decrement, set, reset }];
}

import { useCallback, useRef, useState } from 'react';

export interface UseHoverReturnValue<T extends HTMLElement = any> {
  hovered: boolean;
  ref: React.RefCallback<T | null>;
}

export function useHover<T extends HTMLElement = any>(): UseHoverReturnValue<T> {
  const [hovered, setHovered] = useState(false);
  const previousNode = useRef<HTMLElement>(null);

  const handleMouseEnter = useCallback(() => {
    setHovered(true);
  }, []);

  const handleMouseLeave = useCallback(() => {
    setHovered(false);
  }, []);

  const ref: React.RefCallback<T | null> = useCallback(
    (node) => {
      if (previousNode.current) {
        previousNode.current.removeEventListener('mouseenter', handleMouseEnter);
        previousNode.current.removeEventListener('mouseleave', handleMouseLeave);
      }

      if (node) {
        node.addEventListener('mouseenter', handleMouseEnter);
        node.addEventListener('mouseleave', handleMouseLeave);
      }

      previousNode.current = node;

      return () => {
        previousNode.current = null;
        setHovered(false);
      };
    },
    [handleMouseEnter, handleMouseLeave]
  );

  return { ref, hovered };
}

export namespace useHover {
  export type ReturnValue<T extends HTMLElement> = UseHoverReturnValue<T>;
}

import { useCallback, useMemo, useState } from 'react';

export interface UseStateHistoryHandlers<T> {
  set: (value: T) => void;
  back: (steps?: number) => void;
  forward: (steps?: number) => void;
  reset: () => void;
}

export interface UseStateHistoryValue<T> {
  history: T[];
  current: number;
}

export type UseStateHistoryReturnValue<T> = [
  T,
  UseStateHistoryHandlers<T>,
  UseStateHistoryValue<T>,
];

export function useStateHistory<T>(initialValue: T): UseStateHistoryReturnValue<T> {
  const [state, setState] = useState<UseStateHistoryValue<T>>({
    history: [initialValue],
    current: 0,
  });

  const set = useCallback(
    (val: T) =>
      setState((currentState) => {
        const nextState = [...currentState.history.slice(0, currentState.current + 1), val];
        return {
          history: nextState,
          current: nextState.length - 1,
        };
      }),
    []
  );

  const back = useCallback(
    (steps = 1) =>
      setState((currentState) => ({
        history: currentState.history,
        current: Math.max(0, currentState.current - steps),
      })),
    []
  );

  const forward = useCallback(
    (steps = 1) =>
      setState((currentState) => ({
        history: currentState.history,
        current: Math.min(currentState.history.length - 1, currentState.current + steps),
      })),
    []
  );

  const reset = useCallback(() => {
    setState({ history: [initialValue], current: 0 });
  }, [initialValue]);

  const handlers = useMemo(() => ({ back, forward, reset, set }), [back, forward, reset, set]);

  return [state.history[state.current], handlers, state];
}

import { useEffect, useEffectEvent, useRef } from 'react';

type EventType = MouseEvent | TouchEvent;

const DEFAULT_EVENTS = ['mousedown', 'touchstart'];

export function useClickOutside<T extends HTMLElement = any>(
  callback: (event: EventType) => void,
  events?: string[] | null,
  nodes?: (HTMLElement | null)[],
  enabled: boolean = true
) {
  const ref = useRef<T>(null);
  const eventsList = events || DEFAULT_EVENTS;

  const listener = useEffectEvent((event: Event) => {
    const { target } = event ?? {};
    const shouldIgnore =
      !document.body.contains(target as Node) && (target as Element)?.tagName !== 'HTML';

    if (shouldIgnore) {
      return;
    }

    const path = event.composedPath();

    if (Array.isArray(nodes)) {
      const shouldTrigger = nodes.every((node) => !!node && !path.includes(node));
      shouldTrigger && callback(event as EventType);
    } else if (ref.current && !path.includes(ref.current)) {
      callback(event as EventType);
    }
  });

  const eventsKey = eventsList.join(',');

  useEffect(() => {
    if (!enabled) {
      return undefined;
    }

    const events = eventsKey.split(',');
    events.forEach((fn) => document.addEventListener(fn, listener));

    return () => {
      events.forEach((fn) => document.removeEventListener(fn, listener));
    };
  }, [eventsKey, enabled]);

  return ref;
}

