export class MultiMap<K, V> {
  private _map: Map<K, V[]>;

  constructor() {
    this._map = new Map<K, V[]>();
  }

  set(key: K, value: V) {
    let values = this._map.get(key);
    if (!values) {
      values = [];
      this._map.set(key, values);
    }
    values.push(value);
  }

  get(key: K): V[] {
    return this._map.get(key) || [];
  }

  has(key: K): boolean {
    return this._map.has(key);
  }

  delete(key: K, value: V) {
    const values = this._map.get(key);
    if (!values)
      return;
    if (values.includes(value))
      this._map.set(key, values.filter(v => value !== v));
  }

  deleteAll(key: K) {
    this._map.delete(key);
  }

  hasValue(key: K, value: V): boolean {
    const values = this._map.get(key);
    if (!values)
      return false;
    return values.includes(value);
  }

  get size(): number {
    return this._map.size;
  }

  [Symbol.iterator](): Iterator<[K, V[]]> {
    return this._map[Symbol.iterator]();
  }

  keys(): IterableIterator<K> {
    return this._map.keys();
  }

  values(): Iterable<V> {
    const result: V[] = [];
    for (const key of this.keys())
      result.push(...this.get(key));
    return result;
  }

  clear() {
    this._map.clear();
  }
}

import { ExceptionsHandler } from '../exceptions/exceptions-handler';
import { ExecutionContextHost } from '../helpers/execution-context-host';

export type RouterProxyCallback = <TRequest, TResponse>(
  req: TRequest,
  res: TResponse,
  next: () => void,
) => void | Promise<void>;

export class RouterProxy {
  public createProxy(
    targetCallback: RouterProxyCallback,
    exceptionsHandler: ExceptionsHandler,
  ) {
    return async <TRequest, TResponse>(
      req: TRequest,
      res: TResponse,
      next: () => void,
    ) => {
      try {
        await targetCallback(req, res, next);
      } catch (e) {
        const host = new ExecutionContextHost([req, res, next]);
        exceptionsHandler.next(e, host);
        return res;
      }
    };
  }

  public createExceptionLayerProxy(
    targetCallback: <TError, TRequest, TResponse>(
      err: TError,
      req: TRequest,
      res: TResponse,
      next: () => void,
    ) => void | Promise<void>,
    exceptionsHandler: ExceptionsHandler,
  ) {
    return async <TError, TRequest, TResponse>(
      err: TError,
      req: TRequest,
      res: TResponse,
      next: () => void,
    ) => {
      try {
        await targetCallback(err, req, res, next);
      } catch (e) {
        const host = new ExecutionContextHost([req, res, next]);
        exceptionsHandler.next(e, host);
        return res;
      }
    };
  }
}

import type { StateCreator, StoreMutatorIdentifier } from '../vanilla.ts'
import type { NamedSet } from './devtools.ts'

type Write<T, U> = Omit<T, keyof U> & U

type Action = { type: string }

type StoreRedux<A> = {
  dispatch: (a: A) => A
  dispatchFromDevtools: true
}

type ReduxState<A> = {
  dispatch: StoreRedux<A>['dispatch']
}

type WithRedux<S, A> = Write<S, StoreRedux<A>>

type Redux = <
  T,
  A extends Action,
  Cms extends [StoreMutatorIdentifier, unknown][] = [],
>(
  reducer: (state: T, action: A) => T,
  initialState: T,
) => StateCreator<Write<T, ReduxState<A>>, Cms, [['zustand/redux', A]]>

declare module '../vanilla' {
  interface StoreMutators<S, A> {
    'zustand/redux': WithRedux<S, A>
  }
}

type ReduxImpl = <T, A extends Action>(
  reducer: (state: T, action: A) => T,
  initialState: T,
) => StateCreator<T & ReduxState<A>, [], []>

const reduxImpl: ReduxImpl = (reducer, initial) => (set, _get, api) => {
  type S = typeof initial
  type A = Parameters<typeof reducer>[1]
  ;(api as any).dispatch = (action: A) => {
    ;(set as NamedSet<S>)((state: S) => reducer(state, action), false, action)
    return action
  }
  ;(api as any).dispatchFromDevtools = true

  return { dispatch: (...args) => (api as any).dispatch(...args), ...initial }
}
export const redux = reduxImpl as unknown as Redux

import { useEffect, useState } from 'react';

export const LocationMonitor = {
  _currentHref: globalThis.window?.location.href ?? '',
  _intervalId: null as ReturnType<typeof setInterval> | null,
  _listeners: new Set<(location: Location) => void>(),

  start() {
    if (this._intervalId === null) {
      this._intervalId = setInterval(() => {
        const newLocation = globalThis.window.location;
        if (newLocation.href !== this._currentHref) {
          this._currentHref = newLocation.href;
          this._listeners.forEach((listener) => listener(newLocation));
        }
      }, 100);
    }
  },

  stop() {
    if (this._intervalId !== null) {
      clearInterval(this._intervalId);
      this._intervalId = null;
    }
  },

  subscribe(...listeners: Array<(location: Location) => void>) {
    listeners.forEach((listener) => this._listeners.add(listener));
    this.start();
    return () => {
      listeners.forEach((listener) => this._listeners.delete(listener));
      if (this._listeners.size === 0) {
        this.stop();
      }
    };
  },
};

export const useLocationHash = () => {
  const [hash, setHash] = useState(globalThis.window?.location.hash ?? '');
  useEffect(() => LocationMonitor.subscribe((location) => setHash(location.hash)), []);
  return hash.slice(1);
};

export function share<TValue, TError>(
  _opts?: ShareConfig,
): MonoTypeOperatorFunction<TValue, TError> {
  return (source) => {
    let refCount = 0;

    let subscription: Unsubscribable | null = null;
    const observers: Partial<Observer<TValue, TError>>[] = [];

    function startIfNeeded() {
      if (subscription) {
        return;
      }
      subscription = source.subscribe({
        next(value) {
          for (const observer of observers) {
            observer.next?.(value);
          }
        },
        error(error) {
          for (const observer of observers) {
            observer.error?.(error);
          }
        },
        complete() {
          for (const observer of observers) {
            observer.complete?.();
          }
        },
      });
    }
    function resetIfNeeded() {
      // "resetOnRefCountZero"
      if (refCount === 0 && subscription) {
        const _sub = subscription;
        subscription = null;
        _sub.unsubscribe();
      }
    }

    return observable((subscriber) => {
      refCount++;

      observers.push(subscriber);
      startIfNeeded();
      return {
        unsubscribe() {
          refCount--;
          resetIfNeeded();

          const index = observers.findIndex((v) => v === subscriber);

          if (index > -1) {
            observers.splice(index, 1);
          }
        },
      };
    });
  };
}

const isBuffer = (
    value: unknown,
): value is Uint8Array & { equals(other: Uint8Array): boolean } =>
    typeof Buffer !== "undefined" && Buffer.isBuffer(value)

export const isUint8Array = (value: unknown): value is Uint8Array => {
    if (value instanceof Uint8Array) {
        return true
    }

    if (!ArrayBuffer.isView(value)) {
        return false
    }

    return Object.prototype.toString.call(value) === "[object Uint8Array]"
}

export const areUint8ArraysEqual = (
    left: Uint8Array,
    right: Uint8Array,
): boolean => {
    if (left === right) {
        return true
    }

    if (isBuffer(left) && isBuffer(right)) {
        return left.equals(right)
    }

    if (left.byteLength !== right.byteLength) {
        return false
    }

    for (let index = 0; index < left.byteLength; index++) {
        if (left[index] !== right[index]) {
            return false
        }
    }

    return true
}

const HEX_LOOKUP_TABLE = Array.from({ length: 256 }, (_, i) =>
    i.toString(16).padStart(2, "0"),
)
export const uint8ArrayToHex = (value: Uint8Array): string => {
    if (typeof (value as any).toHex === "function") {
        return (value as any).toHex()
    }

    let hex = ""
    for (let index = 0; index < value.length; index++) {
        hex += HEX_LOOKUP_TABLE[value[index]]
    }
    return hex
}

import * as core from '@actions/core';
import * as exec from '@actions/exec';
import * as fs from 'fs';
import * as path from 'path';

export async function detectChangedTemplates(baseSha: string, headSha: string, workingDir: string): Promise<Map<string, string>> {
  core.info(`Detecting changed .template.json files from ${baseSha} to ${headSha}`);

  let stdout = '';
  await exec.exec('git', ['diff', '--name-status', `${baseSha}...${headSha}`], {
    listeners: {
      stdout: (data: Buffer) => {
        stdout += data.toString();
      }
    }
  });

  const changed = stdout
    .split('\n')
    .filter(line => /^(A|M)\s+.*\.template\.json$/.test(line))
    .map(line => line.trim().split(/\s+/)[1]);

  const fileMapping = new Map<string, string>();

  for (const file of changed) {
    const repoRoot = await exec.getExecOutput('git', ['rev-parse', '--show-toplevel']);
    const fullPath = path.join(repoRoot.stdout.trim(), file);
    console.log('fullpath:', fullPath);
    //Create the safe file name for running security analysis
    const safeName = file.replace(/\//g, '_');
    const safeNameFullPath = path.join(workingDir, safeName);

    //Read the changed file content
    const fileContent = await exec.getExecOutput('git', ['show', `${headSha}:${file}`]);
    fs.writeFileSync(safeNameFullPath, fileContent.stdout);
    fileMapping.set(path.resolve(safeNameFullPath), file);
    core.info(`Copied: ${file}`);
  }

  return fileMapping;
}

import {
  NewChangesetWithCommit,
  VersionType,
  ChangelogFunctions,
  ModCompWithPackage,
} from "@changesets/types";

const getReleaseLine = async (
  changeset: NewChangesetWithCommit,
  _type: VersionType
) => {
  const [firstLine, ...futureLines] = changeset.summary
    .split("\n")
    .map((l) => l.trimEnd());

  let returnVal = `- ${
    changeset.commit ? `${changeset.commit.slice(0, 7)}: ` : ""
  }${firstLine}`;

  if (futureLines.length > 0) {
    returnVal += `\n${futureLines.map((l) => `  ${l}`).join("\n")}`;
  }

  return returnVal;
};

const getDependencyReleaseLine = async (
  changesets: NewChangesetWithCommit[],
  dependenciesUpdated: ModCompWithPackage[]
) => {
  if (dependenciesUpdated.length === 0) return "";

  const changesetLinks = changesets.map(
    (changeset) =>
      `- Updated dependencies${
        changeset.commit ? ` [${changeset.commit.slice(0, 7)}]` : ""
      }`
  );

  const updatedDependenciesList = dependenciesUpdated.map(
    (dependency) => `  - ${dependency.name}@${dependency.newVersion}`
  );

  return [...changesetLinks, ...updatedDependenciesList].join("\n");
};

const defaultChangelogFunctions: ChangelogFunctions = {
  getReleaseLine,
  getDependencyReleaseLine,
};

export default defaultChangelogFunctions;

interface PromiseWithResolvers<T> {
  promise: Promise<T>;
  resolve: (value: T | PromiseLike<T>) => void;
  reject: (reason?: any) => void;
}

function withResolvers<T>(): PromiseWithResolvers<T> {
  const rv = {} as PromiseWithResolvers<T>;
  rv.promise = new Promise<T>((resolve, reject) => {
    rv.resolve = resolve;
    rv.reject = reject;
  });
  return rv;
}

function promiseTry<T>(fn: () => Promise<T>): Promise<T> {
  return new Promise<T>((resolve) => resolve(fn()));
}

export function createPromiseQueue(concurrency: number) {
  const jobs: Array<{
    fn: () => Promise<unknown>;
    resolve: PromiseWithResolvers<unknown>["resolve"];
    reject: PromiseWithResolvers<unknown>["reject"];
  }> = [];

  let active = 0;

  function run() {
    if (active >= concurrency) {
      return;
    }

    const job = jobs.shift();

    if (!job) {
      return;
    }

    active++;

    promiseTry(job.fn).then(
      (result) => {
        active--;
        job.resolve(result);
        run();
      },
      (error) => {
        active--;
        job.reject(error);
        run();
      }
    );
  }

  return {
    add: <T>(fn: () => Promise<T>): Promise<T> => {
      const { promise, resolve, reject } = withResolvers();
      jobs.push({
        fn,
        resolve,
        reject,
      });
      run();
      return promise as Promise<T>;
    },
    setConcurrency: (newConcurrency: number) => {
      concurrency = newConcurrency;
      run();
    },
  };
}

