export interface KeyboardModifiers {
  alt: boolean;
  ctrl: boolean;
  meta: boolean;
  mod: boolean;
  shift: boolean;
}

export interface Hotkey extends KeyboardModifiers {
  key?: string;
}

type CheckHotkeyMatch = (event: KeyboardEvent) => boolean;

const keyNameMap: Record<string, string> = {
  ' ': 'space',
  ArrowLeft: 'arrowleft',
  ArrowRight: 'arrowright',
  ArrowUp: 'arrowup',
  ArrowDown: 'arrowdown',
  Escape: 'escape',
  Esc: 'escape',
  esc: 'escape',
  Enter: 'enter',
  Tab: 'tab',
  Backspace: 'backspace',
  Delete: 'delete',
  Insert: 'insert',
  Home: 'home',
  End: 'end',
  PageUp: 'pageup',
  PageDown: 'pagedown',
  '+': 'plus',
  '-': 'minus',
  '*': 'asterisk',
  '/': 'slash',
};

function normalizeKey(key: string): string {
  const lowerKey = key.replace('Key', '').toLowerCase();
  return keyNameMap[key] || lowerKey;
}

export function parseHotkey(hotkey: string): Hotkey {
  const keys = hotkey
    .toLowerCase()
    .split('+')
    .map((part) => part.trim());

  const modifiers: KeyboardModifiers = {
    alt: keys.includes('alt'),
    ctrl: keys.includes('ctrl'),
    meta: keys.includes('meta'),
    mod: keys.includes('mod'),
    shift: keys.includes('shift'),
  };

  const reservedKeys = ['alt', 'ctrl', 'meta', 'shift', 'mod'];

  const freeKey = keys.find((key) => !reservedKeys.includes(key));

  return {
    ...modifiers,
    key: freeKey === '[plus]' ? '+' : freeKey,
  };
}

function findNextEnabled(
  current: number,
  total: number,
  isItemDisabled: (index: number) => boolean,
  loop: boolean
): number {
  for (let i = current + 1; i < total; i += 1) {
    if (!isItemDisabled(i)) {
      return i;
    }
  }

  if (loop) {
    for (let i = 0; i < current; i += 1) {
      if (!isItemDisabled(i)) {
        return i;
      }
    }
  }

  return current;
}

function findPreviousEnabled(
  current: number,
  total: number,
  isItemDisabled: (index: number) => boolean,
  loop: boolean
): number {
  for (let i = current - 1; i >= 0; i -= 1) {
    if (!isItemDisabled(i)) {
      return i;
    }
  }

  if (loop) {
    for (let i = total - 1; i > current; i -= 1) {
      if (!isItemDisabled(i)) {
        return i;
      }
    }
  }

  return current;
}

function findFirstEnabled(total: number, isItemDisabled: (index: number) => boolean): number {
  for (let i = 0; i < total; i += 1) {
    if (!isItemDisabled(i)) {
      return i;
    }
  }

  return 0;
}

function findLastEnabled(total: number, isItemDisabled: (index: number) => boolean): number {
  for (let i = total - 1; i >= 0; i -= 1) {
    if (!isItemDisabled(i)) {
      return i;
    }
  }

  return 0;
}

export function getFromENV(name: string): string | undefined {
  let value = process.env[name];
  value = value === undefined ? process.env[`npm_config_${name.toLowerCase()}`] : value;
  value = value === undefined ?  process.env[`npm_package_config_${name.toLowerCase()}`] : value;
  return value;
}

export function getAsBooleanFromENV(name: string, defaultValue?: boolean | undefined): boolean {
  const value = getFromENV(name);
  if (value === 'false' || value === '0')
    return false;
  if (value)
    return true;
  return !!defaultValue;
}

export function getPackageManager() {
